def test_open_savings_account_one_cent_below_minimum(verified_customer_client):
    payload = {"initial_deposit": 99.99}
    resp = verified_customer_client.post("/accounts/savings", json=payload)
    assert resp.status_code == 422
    body = resp.json()
    assert "account_id" not in body

def test_open_savings_account_unauthenticated_returns_401(unauthenticated_client):
    payload = {"initial_deposit": 500.00}
    resp = unauthenticated_client.post("/accounts/savings", json=payload)
    assert resp.status_code == 401
    body = resp.json()
    assert "account_id" not in body
